import {
    IMessageDataWrapper,
    IMessageParser,
} from '@nitrots/nitro-renderer/src/core';

export class CancelGatherParser implements IMessageParser {
    private _success: boolean = false;

    public flush(): boolean {
        this._success = false;
        return true;
    }

    public parse(wrapper: IMessageDataWrapper): boolean {
        this._success = wrapper.readBoolean(); // or omit if no data is sent
        return true;
    }

    public get success(): boolean {
        return this._success;
    }
}
